var koringz = {
	_create_xhr_object: function(f) {
		try {
			if (typeof xmlhttp == 'undefined') {
				xmlhttp = new XMLHttpRequest()
			} else {
				try {
					xmlhttp = new ActiveXObject('Microsoft.XMLHTTP')
				} catch (e) {
					console.log(e.message)
				}
			}
		} catch (e) {} finally {
			return xmlhttp
		}
	},
	asyc_xhr_request: function(url, d) {
		var create_xhr_object, default_num= 0, _defaul_object, _str_object, str, c;
		c = {
			lik: url,
			tid: default_num,
			xhr: true
		};
		create_xhr_object = this._create_xhr_object();
		create_xhr_object.open('get', c.lik, c.xhr);
		create_xhr_object.onreadystatechange = function() {
			if (create_xhr_object.readyState == 4) {
				str = create_xhr_object.responseText;
				try {
					if (typeof str != 'string' && typeof str != 'object') {
						return null
					} else {
						_defaul_object = {
							txt: str,
							num: default_num,
							result: false,
							dom: d
						};
						koringz._get_res_content(_defaul_object)
					}
				} catch (e) {}
			}
		}
		create_xhr_object.send(null)
	},
	_get_res_content: function(_new_defaul_object) {
		var myContent, json_data, i, c, f;
		f = {
			_txt: _new_defaul_object.txt,
			_num: _new_defaul_object.num,
			_rst: _new_defaul_object.result,
			_dom: _new_defaul_object.dom
		};
		if (f._dom) {
			var is_dom = f._dom
		}
		if (f._txt) {
			json_data = eval('(' + f._txt + ')')
		}
		koringz._test_demo_one(json_data, is_dom)
	},
	_test_demo_one: function(val, dom) {
		try {
			if (typeof val == 'object') {
				for (i = 0; i < val.length; i++) {
					(function(k) {
						var p, q, get_string, new_value01, new_value02, new_value03, new_value04, new_value05;
						p = k;
						q = ++k;
						get_string = '';
						try {
							if ('string' == typeof get_string) {
								get_string += '<p>' + '<span>' + val[p].shift + '</span>' + val[p].map + '<a href=' + val[p].url + ' title=' + val[p].title + ' class=' + 'cc0' + q + ' >' + val[p].word_links + '</a>' + '</p>';
								if (typeof val[p].shift == 'undefined') {
									return false
								} else if (typeof val[p].shift == 'string') {
									dom.innerHTML += get_string
								}
							}
						} catch (e) {
							console.log(e.message)
						}
					})(i)
				}
			} else {}
		} catch (e) {
			console.log(e.message)
		}
	},
};